const serviceName = variables.service;
const configName = variables.config;
if(serviceName !== "") {
  const searchedService = filteredServices.value.find(obj => obj.serviceName === serviceName);

  // If service exists in CP, set service name, details and fetch configs details and values.
  if(searchedService) {
     actions.setPageVariable("selectedServiceRow",searchedService)
     actions.setPageVariable("selectedService",serviceName)
     actions.setPageVariable("selectedConfig",configName)
    fetchConfigDetails.run({
      onSuccess: () => {
        queries.fetchConfigValues.run({
          onSuccess: ()=> {
            components.allServicesContainer.setTab("t1"); //??
            components.searchByDimensionCollapsibleContainer.(false); //??

          },
          onFailure: ()=> {
            allServicesContainer.setCurrentViewIndex(1); //??
            utils.showNotification({
              title: "Wrong Config Name",
              description: "Config that you're trying to open doesn't exist.",
              notificationType: "error"
            });
            queries.fetchAllConfigs.run();
            queries.fetchRateLimit.run();
          }
        });
      },
      onFailure: () => {
        allServicesContainer.setCurrentViewIndex(1); //??
        utils.showNotification({
          title: "Wrong Config Name",
          description: "Config that you're trying to open doesn't exist.",
          notificationType: "error"
        });
        queries.fetchAllConfigs.run();
        queries.fetchRateLimit.run();
      }
    });

  } else {
    allServicesContainer.setCurrentViewIndex(0); //??
    utils.showNotification({
        title: "Wrong Service Name",
        description: "Service you're trying to open doesn't exist.",
        notificationType: "error"
      }
    );
    return;
  }
}
